class LRUCache {

    private class Node {
        int key;
        int value;
        Node prev;
        Node next;
        Node(int k, int v) {
            key = k;
            value = v;
        }
    }

    private Node head;
    private Node tail;
    private java.util.HashMap<Integer, Node> map;
    private int capacity;
    private int size;

    public LRUCache(int capacity) {
        this.capacity = capacity;
        head = new Node(0, 0);
        tail = new Node(0, 0);
        head.next = tail;
        tail.prev = head;
        map = new java.util.HashMap<>();
        size = 0;
    }

    public int get(int key) {
        if (!map.containsKey(key)) {
            return -1;
        }
        Node node = map.get(key);
        removeNode(node);
        addNodeToFront(node);
        return node.value;
    }

    public void put(int key, int value) {
        if (map.containsKey(key)) {
            Node node = map.get(key);
            node.value = value;
            removeNode(node);
            addNodeToFront(node);
        } else {
            Node newNode = new Node(key, value);
            if (size >= capacity) {
                Node lruNode = tail.prev;
                removeNode(lruNode);
                map.remove(lruNode.key);
                size--;
            }
            addNodeToFront(newNode);
            map.put(key, newNode);
            size++;
        }
    }

    private void removeNode(Node node) {
        Node prev = node.prev;
        Node next = node.next;
        if (prev != null) {
            prev.next = next;
        }
        if (next != null) {
            next.prev = prev;
        }
    }

    private void addNodeToFront(Node node) {
        node.prev = head;
        node.next = head.next;
        head.next.prev = node;
        head.next = node;
    }
}

